from airflow.decorators import task
import great_expectations as gx

@task
def validate_raw_orders(ti):
    df = ti.xcom_pull(task_ids="fetch_orders")
    context = gx.get_context(mode="file")
    checkpoint = context.checkpoints.get("raw_orders_checkpoint")
    result = checkpoint.run(batch_parameters={"dataframe": df})
    if not result.success:
        raise ValueError("Raw order validation failed")

@task
def validate_transformed_orders(ti):
    df = ti.xcom_pull(task_ids="transform_orders")
    context = gx.get_context(mode="file")
    checkpoint = context.checkpoints.get("transformed_orders_checkpoint")
    result = checkpoint.run(batch_parameters={"dataframe": df})
    if not result.success:
        raise ValueError("Transformed order validation failed")
